/**
 * Lightweight markdown renderer — no dependencies.
 * Supports: headings, bold, italic, inline code, code blocks,
 * links, images, blockquotes, lists (ul/ol), tables, hr, paragraphs.
 */
(function () {
  'use strict';

  function escapeHtml(s) {
    return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
  }

  function renderInline(text) {
    return text
      // images
      .replace(/!\[([^\]]*)\]\(([^)]+)\)/g, '<img alt="$1" src="$2" style="max-width:100%">')
      // links
      .replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2" target="_blank" rel="noopener">$1</a>')
      // bold + italic
      .replace(/\*\*\*(.+?)\*\*\*/g, '<strong><em>$1</em></strong>')
      // bold
      .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
      .replace(/__(.+?)__/g, '<strong>$1</strong>')
      // italic
      .replace(/\*(.+?)\*/g, '<em>$1</em>')
      .replace(/_(.+?)_/g, '<em>$1</em>')
      // strikethrough
      .replace(/~~(.+?)~~/g, '<del>$1</del>')
      // inline code
      .replace(/`([^`]+)`/g, '<code>$1</code>');
  }

  function parseMarkdown(src) {
    const lines = src.split('\n');
    const out = [];
    let i = 0;

    while (i < lines.length) {
      const line = lines[i];

      // Fenced code block
      const fenceMatch = line.match(/^```(\w*)/);
      if (fenceMatch) {
        const lang = fenceMatch[1];
        const codeLines = [];
        i++;
        while (i < lines.length && !lines[i].startsWith('```')) {
          codeLines.push(escapeHtml(lines[i]));
          i++;
        }
        i++; // skip closing ```
        const langAttr = lang ? ` class="language-${lang}"` : '';
        out.push(`<pre><code${langAttr}>${codeLines.join('\n')}</code></pre>`);
        continue;
      }

      // Blank line
      if (line.trim() === '') { i++; continue; }

      // Heading
      const headingMatch = line.match(/^(#{1,6})\s+(.+)/);
      if (headingMatch) {
        const level = headingMatch[1].length;
        out.push(`<h${level}>${renderInline(headingMatch[2])}</h${level}>`);
        i++;
        continue;
      }

      // Horizontal rule
      if (/^(-{3,}|\*{3,}|_{3,})\s*$/.test(line)) {
        out.push('<hr>');
        i++;
        continue;
      }

      // Blockquote
      if (line.startsWith('> ') || line === '>') {
        const bqLines = [];
        while (i < lines.length && (lines[i].startsWith('> ') || lines[i] === '>')) {
          bqLines.push(lines[i].replace(/^>\s?/, ''));
          i++;
        }
        out.push(`<blockquote>${parseMarkdown(bqLines.join('\n'))}</blockquote>`);
        continue;
      }

      // Table
      if (line.includes('|') && i + 1 < lines.length && /^\|?\s*[-:]+[-| :]*$/.test(lines[i + 1])) {
        const headerCells = line.split('|').map(c => c.trim()).filter(Boolean);
        i += 2; // skip header + separator
        const rows = [];
        while (i < lines.length && lines[i].includes('|') && lines[i].trim() !== '') {
          rows.push(lines[i].split('|').map(c => c.trim()).filter(Boolean));
          i++;
        }
        let table = '<table><thead><tr>';
        headerCells.forEach(c => { table += `<th>${renderInline(c)}</th>`; });
        table += '</tr></thead><tbody>';
        rows.forEach(row => {
          table += '<tr>';
          row.forEach(c => { table += `<td>${renderInline(c)}</td>`; });
          table += '</tr>';
        });
        table += '</tbody></table>';
        out.push(table);
        continue;
      }

      // Unordered list
      if (/^[\s]*[-*+]\s/.test(line)) {
        const items = [];
        while (i < lines.length && /^[\s]*[-*+]\s/.test(lines[i])) {
          items.push(renderInline(lines[i].replace(/^[\s]*[-*+]\s/, '')));
          i++;
        }
        out.push('<ul>' + items.map(li => `<li>${li}</li>`).join('') + '</ul>');
        continue;
      }

      // Ordered list
      if (/^\s*\d+\.\s/.test(line)) {
        const items = [];
        while (i < lines.length && /^\s*\d+\.\s/.test(lines[i])) {
          items.push(renderInline(lines[i].replace(/^\s*\d+\.\s/, '')));
          i++;
        }
        out.push('<ol>' + items.map(li => `<li>${li}</li>`).join('') + '</ol>');
        continue;
      }

      // Paragraph — collect consecutive non-empty lines
      const paraLines = [];
      while (i < lines.length && lines[i].trim() !== '' &&
             !lines[i].match(/^(#{1,6}\s|```|>\s|[-*+]\s|\d+\.\s|---|\*\*\*|___)/) &&
             !(lines[i].includes('|') && i + 1 < lines.length && /^\|?\s*[-:]+/.test(lines[i+1] || ''))) {
        paraLines.push(lines[i]);
        i++;
      }
      if (paraLines.length) {
        out.push(`<p>${renderInline(paraLines.join('<br>'))}</p>`);
      }
    }

    return out.join('\n');
  }

  // Expose as `marked.parse()` to match the marked.js API
  window.marked = {
    parse: function (src, opts) {
      return parseMarkdown(src || '');
    }
  };
})();
